$(function () {
  "use strict";

  $(".preloader").fadeOut();
  // ==============================================================
  // Theme options
  // ==============================================================
  // ==============================================================
  // sidebar-hover
  // ==============================================================

  $(".left-sidebar").hover(
    function () {
      $(".navbar-header").addClass("expand-logo");
    },
    function () {
      $(".navbar-header").removeClass("expand-logo");
    }
  );
  // this is for close icon when navigation open in mobile view
  $(".nav-toggler").on("click", function () {
    $("#main-wrapper").toggleClass("show-sidebar");
    $(".nav-toggler i").toggleClass("ti-menu");
  });
  $(".nav-lock").on("click", function () {
    $("body").toggleClass("lock-nav");
    $(".nav-lock i").toggleClass("mdi-toggle-switch-off");
    $("body, .page-wrapper").trigger("resize");
  });
  $(".search-box a, .search-box .app-search .srh-btn").on("click", function () {
    $(".app-search").toggle(200);
    $(".app-search input").focus();
  });

  // ==============================================================
  // Right sidebar options
  // ==============================================================
  $(function () {
    $(".service-panel-toggle").on("click", function () {
      $(".customizer").toggleClass("show-service-panel");
    });
    $(".page-wrapper").on("click", function () {
      $(".customizer").removeClass("show-service-panel");
    });
  });
  // ==============================================================
  // This is for the floating labels
  // ==============================================================
  $(".floating-labels .form-control")
    .on("focus blur", function (e) {
      $(this)
        .parents(".form-group")
        .toggleClass("focused", e.type === "focus" || this.value.length > 0);
    })
    .trigger("blur");

  // ==============================================================
  //tooltip
  // ==============================================================
  $(function () {
    $('[data-toggle="tooltip"]').tooltip();
  });
  // ==============================================================
  //Popover
  // ==============================================================
  $(function () {
    $('[data-toggle="popover"]').popover();
  });

  // ==============================================================
  // Perfact scrollbar
  // ==============================================================
  $(".message-center, .customizer-body, .scrollable").perfectScrollbar({
    wheelPropagation: !0,
  });

  /*var ps = new PerfectScrollbar('.message-body');
    var ps = new PerfectScrollbar('.notifications');
    var ps = new PerfectScrollbar('.scroll-sidebar');
    var ps = new PerfectScrollbar('.customizer-body');*/

  // ==============================================================
  // Resize all elements
  // ==============================================================
  $("body, .page-wrapper").trigger("resize");
  $(".page-wrapper").show();
  // ==============================================================
  // To do list
  // ==============================================================
  $(".list-task li label").click(function () {
    $(this).toggleClass("task-done");
  });

  //****************************
  /* This is for the mini-sidebar if width is less then 1170*/
  //****************************
  var setsidebartype = function () {
    var width = window.innerWidth > 0 ? window.innerWidth : this.screen.width;
    if (width < 1170) {
      $("#main-wrapper").attr("data-sidebartype", "mini-sidebar");
    } else {
      $("#main-wrapper").attr("data-sidebartype", "full");
    }
  };
  $(window).ready(setsidebartype);
  $(window).on("resize", setsidebartype);
  //****************************
  /* This is for sidebartoggler*/
  //****************************
  $(".sidebartoggler").on("click", function () {
    $("#main-wrapper").toggleClass("mini-sidebar");
    if ($("#main-wrapper").hasClass("mini-sidebar")) {
      $(".sidebartoggler").prop("checked", !0);
      $("#main-wrapper").attr("data-sidebartype", "mini-sidebar");
    } else {
      $(".sidebartoggler").prop("checked", !1);
      $("#main-wrapper").attr("data-sidebartype", "full");
    }
  });
  $('#logoutLink').on('click', function (event) {
    event.preventDefault();
    Swal.fire({
      title: ajaxErrorTranslations.logout_confirm_title,
      text: ajaxErrorTranslations.logout_confirm_text,
      icon: 'warning',
      showCancelButton: true,
      confirmButtonText: ajaxErrorTranslations.logout_button,
      cancelButtonText: ajaxErrorTranslations.cancel
    }).then((result) => {
      if (!result.isConfirmed) {
        return;
      }
      const $btn = $('#logoutLink');
      const originalHtml = $btn.html();
      $btn.html(
        '<span class="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>' +
        ajaxErrorTranslations.processing
      );
      const clearJwtCookie = function () {
        document.cookie = "jwt_token=; path=/; max-age=0; SameSite=Lax";
      };
      const jwtToken = typeof getCookie === 'function' ? getCookie('jwt_token') : null;
      const performWebLogout = function () {
        $.ajax({
          url: logoutUrl,
          type: 'GET',
          headers: {
            'Accept': 'application/json',
            'X-Requested-With': 'XMLHttpRequest'
          },
          success: function (response) {
            clearJwtCookie();
            if (response && response.redirect_url) {
              window.location.href = response.redirect_url;
            } else if (typeof loginUrl !== 'undefined') {
              window.location.href = loginUrl;
            } else {
              console.error("No redirect URL returned.");
              $btn.html(originalHtml);
            }
          },
          error: function (xhr) {
            console.error("Logout Error:", xhr.responseText);
            Swal.fire({
              icon: 'error',
              title: ajaxErrorTranslations.server_error_title,
              text: ajaxErrorTranslations.server_error_text,
              confirmButtonText: ajaxErrorTranslations.ok
            });
            clearJwtCookie();
            $btn.html(originalHtml);
          }
        });
      };
      if (jwtToken) {
        $.ajax({
          url: '/api/v1/admin/logout',
          type: 'POST',
          headers: {
            'Authorization': 'Bearer ' + jwtToken,
            'Accept': 'application/json',
            'X-Requested-With': 'XMLHttpRequest'
          },
          complete: function () {
            performWebLogout();
          }
        });
      } else {
        performWebLogout();
      }
    });
  });
});
$(document).ajaxError(function (event, xhr, settings, error) {

  console.group("AJAX Error Details");
  console.error("URL:", settings.url);
  console.error("Status:", xhr.status);
  console.error("Response:", xhr.responseText);
  console.groupEnd();
  if (xhr.status === 401) {
    Swal.fire({
      title: ajaxErrorTranslations.unauthorized_title,
      text: ajaxErrorTranslations.unauthorized_text,
      icon: 'warning',
      confirmButtonText: ajaxErrorTranslations.go_to_login
    }).then(() => {
      window.location.href = loginUrl;
    });
  }
  else if (xhr.status === 419) {
    Swal.fire({
      title: ajaxErrorTranslations.session_expired_title,
      text: ajaxErrorTranslations.session_expired_text,
      icon: 'warning',
      confirmButtonText: ajaxErrorTranslations.session_expired_button
    }).then((result) => {
      if (result.isConfirmed) location.reload();
    });
  }
  else if (xhr.status === 403) {
    Swal.fire({
      title: ajaxErrorTranslations.forbidden_title,
      text: ajaxErrorTranslations.forbidden_text,
      icon: 'error',
      confirmButtonText: ajaxErrorTranslations.ok
    });
  }
  else if (xhr.status === 404) {
    Swal.fire({
      title: ajaxErrorTranslations.not_found_title,
      text: ajaxErrorTranslations.not_found_text,
      icon: 'error',
      confirmButtonText: ajaxErrorTranslations.ok
    });
  }
  else if (xhr.status >= 500) {
    Swal.fire({
      title: ajaxErrorTranslations.server_error_title,
      text: ajaxErrorTranslations.server_error_text,
      icon: 'error',
      confirmButtonText: ajaxErrorTranslations.ok
    });
  }
});
$('body').on('keyup', '.number-decimal-only', function () {
  this.value = this.value.replace(/[^0-9\.]/g, '');
  var dec = this.getAttribute('decimals');
  var regex = new RegExp("(\\.\\d{" + dec + "})\\d+", "g");
  this.value = this.value.replace(regex, '$1');
});
$('body').on('keyup', '.number-only', function () {
  this.value = this.value.replace(/[^0-9\.]/g, '');
});
